let currentOutreach=null; let currentMessageType='email';
function getOutreachInputs(){return {account:$('writerAccount').value.trim()||'Wichita-area manufacturer', context:$('writerContext').value.trim(), persona:$('writerPersona').value, angle:outreachAngles[$('writerAngle').value], note:$('writerNote').value.trim()};}
function makeOutreach(){const i=getOutreachInputs(); const safeName=i.account; const offer=i.angle.offer; const proof=i.angle.proof; const note=i.note;
 const email=`Subject: Practical TCAS idea for ${safeName}\n\nHi [Name],\n\nI’m reaching out from TCAS because we work with manufacturers and machine builders around automation parts, controls support, and line-card solutions.\n\nI do not want to assume what you need without seeing the equipment, but ${i.context.toLowerCase()} is exactly the kind of environment where a short review can uncover useful next steps.\n\nThe practical idea: ${offer}.\n\nWhat TCAS can help identify:\n• parts or product families already in the plant/machine\n• obsolete or hard-to-source components\n• replacement paths and spares\n• sensing, safety, HMI, drive, panel, or gateway opportunities\n• what should become a quote now vs. what needs engineering verification\n\n${note}\n\nWould it be worth a 15-minute conversation to see if there is a useful first review we can do?\n\nThanks,\nAndrew / TCAS`;
 const linkedin=`Hi [Name] — I’m with TCAS. We help manufacturers and machine builders turn real machine/controls needs into practical parts and support plans.\n\nFor ${safeName}, I thought there may be a useful angle around ${i.angle.label}: ${offer}.\n\nNo pitch or assumptions — I’d be curious if a short review of current machines, obsolete parts, or controls/sensing needs would be useful.`;
 const call=`Quick opener:\n\n“Hi [Name], this is Andrew with TCAS. I’m not calling with a generic catalog pitch. We’re looking at Wichita-area machine builders and manufacturers where TCAS can help turn real machine issues, obsolete parts, or new product updates into practical replacement and support plans. Is there someone who handles controls, maintenance, or automation parts that I should talk with?”`;
 const voicemail=`Hi [Name], this is Andrew with TCAS. I’m calling because we’re helping manufacturers and machine builders with practical automation parts support: obsolete components, replacement paths, sensing/vision, controls documentation, and quote-ready next steps. I’ll send a short note as well. My number is [phone]. Again, Andrew with TCAS.`;
 const followup=`Follow-up sequence:\n\nDay 1 — Email with specific angle: ${i.angle.label}.\nDay 3 — Call opener asking for engineering/maintenance contact.\nDay 5 — Send one useful checklist: obsolete parts, controls backups, spare drives, sensing/vision, panel/network reliability.\nDay 10 — Short close-the-loop note: “Should I leave this alone, or is there a better person for controls/maintenance/automation parts?”\n\nApproval gate: do not send until TCAS reviews account fit, contact accuracy, and whether the angle is appropriate.`;
 currentOutreach={...i,email,linkedin,call,voicemail,followup,proof}; renderOutreach('email'); log(`Generated outreach for ${safeName} · ${i.angle.label}`);}
function renderOutreach(type=currentMessageType){ if(!currentOutreach) makeOutreach(); currentMessageType=type; document.querySelectorAll('.tab').forEach(b=>b.classList.toggle('active',b.dataset.message===type)); const labels={email:'Email',linkedin:'LinkedIn',call:'Call opener',voicemail:'Voicemail',followup:'Follow-up sequence'}; $('writerTitle').textContent=labels[type]; $('writerText').textContent=currentOutreach[type]; $('writerProof').innerHTML=currentOutreach.proof.map(x=>`<li>${x}</li>`).join('');}
function addOutreachToQueue(){ if(!currentOutreach) makeOutreach(); const item={id:`outreach-${Date.now()}`, playId:`outreach-${currentOutreach.account}`, created:new Date().toISOString(), account:currentOutreach.account, signal:`Outreach draft: ${currentOutreach.angle.label}`, line:'TCAS business development', lane:'Outreach', priority:'A-', confidence:'Draft needs account verification', value:'Pipeline creation', buyer:currentOutreach.persona, focus:currentOutreach.angle.label, status:'needs_review', summary:`Outreach sequence drafted for ${currentOutreach.account} targeting ${currentOutreach.persona}. Angle: ${currentOutreach.angle.label}.`, pkg:['Email draft','LinkedIn note','Call opener','Voicemail','Follow-up sequence'], draft:currentOutreach.email+'\n\n--- LinkedIn ---\n'+currentOutreach.linkedin+'\n\n--- Call opener ---\n'+currentOutreach.call+'\n\n--- Voicemail ---\n'+currentOutreach.voicemail+'\n\n--- Follow-up ---\n'+currentOutreach.followup, crm:`account: ${currentOutreach.account}\nlane: Outreach\nbuyer: ${currentOutreach.persona}\nangle: ${currentOutreach.angle.label}\nstatus: needs_review\nnext_step: verify contact and approve send`}; queue.unshift(item); saveQueue(); log(`Added outreach draft to approval queue: ${currentOutreach.account}`);}
function initOutreachWriter(){ if(!$('generateOutreachBtn')) return; $('generateOutreachBtn').onclick=makeOutreach; $('copyEmailOutreachBtn').onclick=()=>{ if(!currentOutreach) makeOutreach(); navigator.clipboard?.writeText(currentOutreach.email); log('Copied outreach email'); }; $('copyLinkedInBtn').onclick=()=>{ if(!currentOutreach) makeOutreach(); navigator.clipboard?.writeText(currentOutreach.linkedin); log('Copied LinkedIn outreach'); }; $('addOutreachQueueBtn').onclick=addOutreachToQueue; document.querySelectorAll('.tab').forEach(b=>b.onclick=()=>renderOutreach(b.dataset.message)); ['writerAccount','writerContext','writerPersona','writerAngle','writerNote'].forEach(id=>$(id).addEventListener('input',()=>makeOutreach())); makeOutreach();}

