function initObsoleteTool(){
  if(!$('obsoleteVendor')) return;
  $('obsoleteVendor').innerHTML = obsoleteVendors.map((v,i)=>`<option value="${i}">${v.vendor} (${v.alias})</option>`).join('');
  $('obsoleteVendor').onchange=buildObsoletePacket;
  $('obsoletePart').oninput=buildObsoletePacket;
  $('obsoleteAccount').oninput=buildObsoletePacket;
  $('researchObsoleteBtn').onclick=buildObsoletePacket;
  $('addObsoleteQueueBtn').onclick=addObsoleteToQueue;
  $('copyObsoleteBtn').onclick=()=>{ navigator.clipboard?.writeText($('obsoletePacket').textContent); log('Copied obsolete/discontinued quote pack'); };
  $('exportObsoleteBtn').onclick=exportObsoleteCsv;
  buildObsoletePacket();
}
function selectedObsoleteVendor(){ return obsoleteVendors[Number($('obsoleteVendor').value||0)]; }
function buildObsoletePacket(){
  const v=selectedObsoleteVendor(); const part=$('obsoletePart').value.trim()||'[part number]'; const account=$('obsoleteAccount').value.trim()||'[customer/site]';
  $('obsConfidence').textContent=v.confidence; $('obsAngle').textContent=v.angle.split(' / ')[0];
  const text=`2026 DISCONTINUED / OBSOLETE RESEARCH PACKET\n\nAccount/site: ${account}\nManufacturer: ${v.vendor}\nPart/family: ${part}\nKnown source status: ${v.status}\nConfidence: ${v.confidence}\nSales angle: ${v.angle}\nExample/use case: ${v.example}\n\nResearch workflow:\n${v.workflow.map((x,i)=>`${i+1}. ${x}`).join('\n')}\n\nQuote-safe next action:\nVerify exact catalog number, firmware/series, installed application, replacement compatibility, stock/lead time, and safety/controls impact before quoting or emailing customer.\n\nTCAS packet fields to create:\n- lifecycle status\n- discontinued/end-of-life date if available\n- last-time-buy / last-ship / repair window if listed\n- successor/replacement part\n- required compatibility checks\n- TCAS line-card fit\n- inventory/spares action\n- customer-safe outreach draft\n- source URL evidence`;
  $('obsoletePacket').textContent=text;
  $('obsoleteLinks').innerHTML=[v.source,v.source2].filter(Boolean).map((url,i)=>`<a class="btn ghost" target="_blank" rel="noreferrer" href="${url}">${i===0?v.sourceLabel:'Additional source'}</a>`).join('');
  log(`Built obsolete research packet: ${v.vendor} · ${part}`);
}
function addObsoleteToQueue(){
  const v=selectedObsoleteVendor(); const part=$('obsoletePart').value.trim()||'[part number]'; const account=$('obsoleteAccount').value.trim()||'[customer/site]';
  buildObsoletePacket();
  const packet={ id:`obsolete-${Date.now()}`, playId:`obsolete-${v.vendor}-${part}`, created:new Date().toISOString(), account, signal:`Obsolete/discontinued research: ${part}`, line:v.vendor, lane:'Obsolescence research', priority:v.confidence==='High'||v.confidence.startsWith('High')?'A':'B+', confidence:v.confidence, value:'TBD after part/stock check', buyer:'Maintenance / engineering / purchasing', focus:'discontinued product conversion', status:'needs_review', summary:`${account} has a potential discontinued/obsolete ${v.vendor} part or family (${part}). ${v.status}. Sales angle: ${v.angle}.`, pkg:['Lifecycle/source verification','Replacement/successor lookup','Spare/stock/last-time-buy check','Compatibility and migration risk list','Customer-safe quote/update packet'], draft:$('obsoletePacket').textContent, crm:`account: ${account}\nsignal: obsolete/discontinued research\nmanufacturer_line: ${v.vendor}\npart_or_family: ${part}\nlane: Obsolescence research\nconfidence: ${v.confidence}\nsource: ${v.source}\nstatus: needs_review\nnext_step: verify exact part status and replacement before outreach` };
  queue.unshift(packet); saveQueue(); log(`Added obsolete opportunity to queue: ${v.vendor} · ${part}`);
}
function exportObsoleteCsv(){
  const rows=[['vendor','alias','confidence','status','angle','example','primary_source','additional_source']].concat(obsoleteVendors.map(v=>[v.vendor,v.alias,v.confidence,v.status,v.angle,v.example,v.source,v.source2||'']));
  const csv=rows.map(r=>r.map(csvEscape).join(',')).join('\n'); const blob=new Blob([csv],{type:'text/csv'}); const url=URL.createObjectURL(blob); const a=document.createElement('a'); a.href=url; a.download='tcas-2026-obsolete-research-vendors.csv'; a.click(); URL.revokeObjectURL(url); log('Exported 2026 obsolete vendor research CSV');
}

